"use client";

import React, { useRef, useState, useEffect } from 'react';
import { Stage, Layer, Line, Circle, Rect, Image as KonvaImage } from 'react-konva';
import { useBoardStore, Point } from '../store/useBoardStore';
import Konva from 'konva';

export default function TacticsCanvas() {
  const { 
    activeTool, zoom, stagePosition, setZoomByWheel, setStagePosition,
    elements, addElement, updateElement, removeElement, backgroundImage 
  } = useBoardStore();

  const stageRef = useRef<Konva.Stage>(null);

  // Local state for current drawing action before committing to store (improves performance during fast drags)
  const [isDrawing, setIsDrawing] = useState(false);
  const [currentId, setCurrentId] = useState<string | null>(null);

  // Resize canvas to window
  const [windowSize, setWindowSize] = useState({ width: 0, height: 0 });
  useEffect(() => {
    const handleResize = () => setWindowSize({ width: window.innerWidth, height: window.innerHeight });
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleWheel = (e: any) => {
    e.evt.preventDefault();
    const stage = stageRef.current;
    if (!stage) return;

    // Zoom by 5% per wheel click
    const scaleBy = e.evt.deltaY < 0 ? 1.05 : 0.95;
    const pointer = stage.getPointerPosition();
    if (!pointer) return;

    setZoomByWheel(scaleBy, pointer, stagePosition);
  };

  const generateId = () => Math.random().toString(36).substr(2, 9);

  const handlePointerDown = (e: any) => {
    // If panning tool or middle mouse button, we allow native konva draggable
    if (activeTool === 'pan' || activeTool === 'select') return;
    if (e.evt.button !== 0) return; // Only left click

    const stage = stageRef.current;
    if (!stage) return;

    const pointer = stage.getRelativePointerPosition();
    if (!pointer) return;

    setIsDrawing(true);
    const id = generateId();
    setCurrentId(id);

    if (activeTool === 'pen' || activeTool === 'laser') {
      addElement({
        id,
        type: 'line',
        points: [pointer.x, pointer.y],
        color: activeTool === 'laser' ? '#E8A44A' : '#C47C2B',
        strokeWidth: activeTool === 'laser' ? 6 : 4,
        isLaser: activeTool === 'laser'
      });
    } else if (activeTool === 'circle' || activeTool === 'rectangle') {
      addElement({
        id,
        type: activeTool,
        x: pointer.x,
        y: pointer.y,
        width: 0,
        height: 0,
        radius: 0,
        color: 'transparent', // Fill transparent for tactical borders
        strokeWidth: 4,
      });
    }
  };

  const handlePointerMove = (e: any) => {
    if (!isDrawing || !currentId) return;

    const stage = stageRef.current;
    if (!stage) return;

    const pointer = stage.getRelativePointerPosition();
    if (!pointer) return;

    const currentElement = elements.find(el => el.id === currentId);
    if (!currentElement) return;

    if (activeTool === 'pen' || activeTool === 'laser') {
      const newPoints = currentElement.points ? [...currentElement.points, pointer.x, pointer.y] : [pointer.x, pointer.y];
      updateElement(currentId, { points: newPoints });
    } else if (activeTool === 'rectangle') {
      updateElement(currentId, {
        width: pointer.x - (currentElement.x || 0),
        height: pointer.y - (currentElement.y || 0)
      });
    } else if (activeTool === 'circle') {
      const dx = pointer.x - (currentElement.x || 0);
      const dy = pointer.y - (currentElement.y || 0);
      const radius = Math.sqrt(dx * dx + dy * dy);
      updateElement(currentId, { radius });
    }
  };

  const handlePointerUp = () => {
    if (!isDrawing || !currentId) return;
    setIsDrawing(false);

    // If it was a laser, trigger timeout to remove it
    if (activeTool === 'laser') {
      const idToRemove = currentId;
      setTimeout(() => {
        removeElement(idToRemove);
      }, 2500); // Fades/removes after 2.5s
    }
    setCurrentId(null);
  };

  if (windowSize.width === 0) return null; // Avoid render before client size known

  return (
    <div className="absolute inset-0 bg-[#0F0A06] overflow-hidden cursor-crosshair">
      <Stage
        width={windowSize.width}
        height={windowSize.height}
        onWheel={handleWheel}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        // Pan tool logic
        draggable={activeTool === 'pan'}
        onDragEnd={(e) => setStagePosition({ x: e.target.x(), y: e.target.y() })}
        x={stagePosition.x}
        y={stagePosition.y}
        scaleX={zoom}
        scaleY={zoom}
        ref={stageRef}
      >
        <Layer id="background">
          {backgroundImage && (
            <KonvaImage 
              image={backgroundImage} 
              // Center image optionally if you want, or just let it be at 0,0
              x={0} 
              y={0} 
              opacity={0.8}
            />
          )}
        </Layer>

        <Layer id="drawings">
          {elements.map((el) => {
            if (el.type === 'line') {
              return (
                <Line
                  key={el.id}
                  points={el.points || []}
                  stroke={el.color}
                  strokeWidth={el.strokeWidth}
                  tension={0.5} // Smoothes freehand lines
                  lineCap="round"
                  lineJoin="round"
                  // Laser glow bindings
                  shadowColor={el.isLaser ? el.color : 'transparent'}
                  shadowBlur={el.isLaser ? 15 : 0}
                  opacity={el.isLaser ? 0.9 : 1}
                />
              );
            }
            if (el.type === 'rectangle') {
              return (
                <Rect
                  key={el.id}
                  x={el.x}
                  y={el.y}
                  width={el.width || 0}
                  height={el.height || 0}
                  stroke="#C47C2B"
                  strokeWidth={4}
                  fill="rgba(196,124,43,0.1)"
                />
              );
            }
            if (el.type === 'circle') {
              return (
                <Circle
                  key={el.id}
                  x={el.x}
                  y={el.y}
                  radius={el.radius || 0}
                  stroke="#C47C2B"
                  strokeWidth={4}
                  fill="rgba(196,124,43,0.1)"
                />
              );
            }
            return null;
          })}
        </Layer>
      </Stage>
    </div>
  );
}

"use client";

import { useBoardStore, Tool } from "../store/useBoardStore";
import { 
  Pointer, Hand, Pen, Zap, Circle, Square, 
  ZoomIn, ZoomOut, Image as ImageIcon, Trash2
} from "lucide-react";
import { useState, useRef } from "react";

export default function Toolbar() {
  const { 
    activeTool, setTool, zoom, setZoom, 
    setBackgroundImage, clearElements 
  } = useBoardStore();

  const [imageUrl, setImageUrl] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleToolClick = (tool: Tool) => setTool(tool);

  // Zoom controls
  const handleZoomIn = () => setZoom(Math.min(zoom * 1.2, 10));
  const handleZoomOut = () => setZoom(Math.max(zoom / 1.2, 0.1));

  // Image handling
  const handleLoadUrl = () => {
    if (!imageUrl) return;
    const img = new window.Image();
    img.src = imageUrl;
    img.crossOrigin = "Anonymous";
    img.onload = () => setBackgroundImage(img);
    setImageUrl("");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new window.Image();
      img.src = event.target?.result as string;
      img.onload = () => setBackgroundImage(img);
    };
    reader.readAsDataURL(file);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  const ToolBtn = ({ tool, icon: Icon, label }: { tool: Tool, icon: any, label: string }) => {
    const isActive = activeTool === tool;
    return (
      <button
        onClick={() => handleToolClick(tool)}
        title={label}
        className={`p-2 rounded-md transition-all duration-200 ${
          isActive 
            ? "bg-[#C47C2B] text-[#0A0705] shadow-[0_0_15px_rgba(196,124,43,0.4)]" 
            : "text-[#F5ECD7] hover:bg-[#2A1F15] hover:text-[#E8A44A]"
        }`}
      >
        <Icon size={20} />
      </button>
    );
  };

  return (
    <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 flex flex-col md:flex-row items-center gap-4 bg-[#0A0705CC] backdrop-blur-md border border-[#2A1F15] rounded-[12px] p-2 shadow-2xl">

      {/* Primary Tools */}
      <div className="flex items-center gap-1 border-r border-[#2A1F15] pr-4">
        <ToolBtn tool="select" icon={Pointer} label="Select Tool (V)" />
        <ToolBtn tool="pan" icon={Hand} label="Pan Tool (H or Space)" />
        <ToolBtn tool="pen" icon={Pen} label="Pen Tool (P)" />
        <ToolBtn tool="laser" icon={Zap} label="Laser Tool (L) - Fades quickly" />
        <ToolBtn tool="circle" icon={Circle} label="Draw Circle (C)" />
        <ToolBtn tool="rectangle" icon={Square} label="Draw Rectangle (R)" />
      </div>

      {/* Viewport / Actions */}
      <div className="flex items-center gap-2 border-r border-[#2A1F15] pr-4">
        <button onClick={handleZoomOut} className="p-2 text-[#7A6A55] hover:text-[#F5ECD7] transition-colors"><ZoomOut size={18} /></button>
        <span className="text-[#F5ECD7] font-inter text-xs font-medium w-12 text-center">
          {Math.round(zoom * 100)}%
        </span>
        <button onClick={handleZoomIn} className="p-2 text-[#7A6A55] hover:text-[#F5ECD7] transition-colors"><ZoomIn size={18} /></button>

        <button 
          onClick={clearElements} 
          title="Clear all drawings"
          className="p-2 text-red-500/80 hover:text-red-400 hover:bg-red-500/10 rounded overflow-hidden transition-all ml-2"
        >
          <Trash2 size={18} />
        </button>
      </div>

      {/* Map Importer */}
      <div className="flex items-center gap-2">
        <div className="flex bg-[#1A0F08] border border-[#2A1F15] rounded overflow-hidden">
          <input 
            type="text" 
            value={imageUrl}
            onChange={(e) => setImageUrl(e.target.value)}
            placeholder="Paste Map URL..."
            className="bg-transparent text-[#F5ECD7] text-xs font-inter px-3 py-1.5 w-[140px] focus:outline-none"
            onKeyDown={(e) => e.key === 'Enter' && handleLoadUrl()}
          />
          <button 
            onClick={handleLoadUrl}
            className="bg-[#2A1F15] text-[#C47C2B] text-xs font-sora font-semibold px-3 hover:bg-[#C47C2B] hover:text-[#0A0705] transition-colors"
          >
            Load
          </button>
        </div>

        <span className="text-[#7A6A55] text-xs px-1">or</span>

        <input 
          type="file" 
          accept="image/png, image/jpeg, image/webp" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleFileUpload}
        />
        <button 
          onClick={() => fileInputRef.current?.click()}
          className="flex items-center gap-2 bg-[#2A1F15] text-[#F5ECD7] hover:text-[#C47C2B] hover:border-[#C47C2B] border border-transparent transition-all px-3 py-1.5 rounded text-xs font-sora"
        >
          <ImageIcon size={14} /> Upload
        </button>
      </div>

    </div>
  );
}
